/**
 * A web endpoint connection-related message.
 *
 * Modal's internal web endpoint runtime effectively acts as a global web server
 * that schedules requests to tasks that are spawned on-demand, so we need an
 * internal protocol to model HTTP requests. This is that protocol.
 *
 * We base this protocol on Python's ASGI specification, which is a popular
 * interface between applications and web servers.
 *
 * ASGI Spec: https://asgi.readthedocs.io/en/latest/specs/www.html
 */
export interface Asgi {
  http?: Asgi_Http | undefined;
  httpRequest?: Asgi_HttpRequest | undefined;
  httpResponseStart?: Asgi_HttpResponseStart | undefined;
  httpResponseBody?: Asgi_HttpResponseBody | undefined;
  httpResponseTrailers?: Asgi_HttpResponseTrailers | undefined;
  httpDisconnect?: Asgi_HttpDisconnect | undefined;
  websocket?: Asgi_Websocket | undefined;
  websocketConnect?: Asgi_WebsocketConnect | undefined;
  websocketAccept?: Asgi_WebsocketAccept | undefined;
  websocketReceive?: Asgi_WebsocketReceive | undefined;
  websocketSend?: Asgi_WebsocketSend | undefined;
  websocketDisconnect?: Asgi_WebsocketDisconnect | undefined;
  websocketClose?: Asgi_WebsocketClose | undefined;
}

/** Message of type "http" (connection scope) */
export interface Asgi_Http {
  httpVersion: string;
  method: string;
  scheme: string;
  path: string;
  queryString: Uint8Array;
  /** Flat list of alternating header names and values */
  headers: Uint8Array[];
  clientHost?: string | undefined;
  clientPort?: number | undefined;
}

/** Message of type "http.request" */
export interface Asgi_HttpRequest {
  body: Uint8Array;
  moreBody: boolean;
}

/** Message of type "http.response.start" */
export interface Asgi_HttpResponseStart {
  status: number;
  /** Flat list of alternating header names and values */
  headers: Uint8Array[];
  trailers: boolean;
}

/** Message of type "http.response.body" */
export interface Asgi_HttpResponseBody {
  body: Uint8Array;
  moreBody: boolean;
}

/** Message of type "http.response.trailers" */
export interface Asgi_HttpResponseTrailers {
  /** Flat list of alternating header names and values */
  headers: Uint8Array[];
  moreTrailers: boolean;
}

/** Message of type "http.disconnect" */
export interface Asgi_HttpDisconnect {
}

/** Message of type "websocket" (connection scope) */
export interface Asgi_Websocket {
  /** We don't support RFC 8441 yet, so this will always be "1.1" */
  httpVersion: string;
  scheme: string;
  path: string;
  queryString: Uint8Array;
  /** Flat list of alternating header names and values */
  headers: Uint8Array[];
  clientHost?: string | undefined;
  clientPort?: number | undefined;
  subprotocols: string[];
}

