export interface ClassParameterInfo {
  format: ClassParameterInfo_ParameterSerializationFormat;
  /** only set for PARAM_SERIALIZATION_FORMAT_PROTO */
  schema: ClassParameterSpec[];
}

export enum ClassParameterInfo_ParameterSerializationFormat {
  PARAM_SERIALIZATION_FORMAT_UNSPECIFIED = 0,
  /** PARAM_SERIALIZATION_FORMAT_PICKLE - legacy format - pickle of (args, kwargs) tuple */
  PARAM_SERIALIZATION_FORMAT_PICKLE = 1,
  /** PARAM_SERIALIZATION_FORMAT_PROTO - new format using api.FunctionParameterSet */
  PARAM_SERIALIZATION_FORMAT_PROTO = 2,
  UNRECOGNIZED = -1,
}

export function classParameterInfo_ParameterSerializationFormatFromJSON(
  object: any,
): ClassParameterInfo_ParameterSerializationFormat {
  switch (object) {
    case 0:
    case "PARAM_SERIALIZATION_FORMAT_UNSPECIFIED":
      return ClassParameterInfo_ParameterSerializationFormat.PARAM_SERIALIZATION_FORMAT_UNSPECIFIED;
    case 1:
    case "PARAM_SERIALIZATION_FORMAT_PICKLE":
      return ClassParameterInfo_ParameterSerializationFormat.PARAM_SERIALIZATION_FORMAT_PICKLE;
    case 2:
    case "PARAM_SERIALIZATION_FORMAT_PROTO":
      return ClassParameterInfo_ParameterSerializationFormat.PARAM_SERIALIZATION_FORMAT_PROTO;
    case -1:
    case "UNRECOGNIZED":
    default:
      return ClassParameterInfo_ParameterSerializationFormat.UNRECOGNIZED;
  }
}

export function classParameterInfo_ParameterSerializationFormatToJSON(
  object: ClassParameterInfo_ParameterSerializationFormat,
): string {
  switch (object) {
    case ClassParameterInfo_ParameterSerializationFormat.PARAM_SERIALIZATION_FORMAT_UNSPECIFIED:
      return "PARAM_SERIALIZATION_FORMAT_UNSPECIFIED";
    case ClassParameterInfo_ParameterSerializationFormat.PARAM_SERIALIZATION_FORMAT_PICKLE:
      return "PARAM_SERIALIZATION_FORMAT_PICKLE";
    case ClassParameterInfo_ParameterSerializationFormat.PARAM_SERIALIZATION_FORMAT_PROTO:
      return "PARAM_SERIALIZATION_FORMAT_PROTO";
    case ClassParameterInfo_ParameterSerializationFormat.UNRECOGNIZED:
    default:
      return "UNRECOGNIZED";
  }
}

export interface ClassParameterSet {
  /**
   * NOTE: adding additional *fields* here can invalidate function lookups
   *  since we use the serialized message as the bound function identifier
   *  for parameter-bound classes. Modify with *caution*
   */
  parameters: ClassParameterValue[];
}

/** TODO: rename into NamedPayloadType or similar */
export interface ClassParameterSpec {
  name: string;
  /** TODO: deprecate - use full_type instead */
  type: ParameterType;
  hasDefault: boolean;
  /** Default *values* are only registered for class parameters */
  stringDefault?: string | undefined;
  intDefault?: number | undefined;
  pickleDefault?: Uint8Array | undefined;
  bytesDefault?: Uint8Array | undefined;
  boolDefault?:
    | boolean
    | undefined;
  /** supersedes `type` */
  fullType: GenericPayloadType | undefined;
}

/** TODO: rename into NamedPayloadValue */
export interface ClassParameterValue {
  /**
   * NOTE: adding additional *fields* here can invalidate function lookups
   *  since we use the serialized message as the bound function identifier
   *  for parameter-bound classes. Modify with *caution*
   */
  name: string;
  type: ParameterType;
  stringValue?: string | undefined;
  intValue?: number | undefined;
  pickleValue?: Uint8Array | undefined;
  bytesValue?: Uint8Array | undefined;
  boolValue?: boolean | undefined;
}

