export interface FunctionMessage {
  moduleName: string;
  functionName: string;
  mountIds: string[];
  imageId: string;
  functionSerialized: Uint8Array;
  definitionType: Function_DefinitionType;
  functionType: Function_FunctionType;
  resources: Resources | undefined;
  secretIds: string[];
  rateLimit: RateLimit | undefined;
  webhookConfig: WebhookConfig | undefined;
  sharedVolumeMounts: SharedVolumeMount[];
  proxyId?: string | undefined;
  retryPolicy:
    | FunctionRetryPolicy
    | undefined;
  /** To be replaced by autoscaler_settings.max_containers */
  concurrencyLimit: number;
  timeoutSecs: number;
  ptyInfo: PTYInfo | undefined;
  classSerialized: Uint8Array;
  /** To be replaced by autoscaler_settings.scaledown_period */
  taskIdleTimeoutSecs: number;
  /** Deprecated at some point */
  cloudProvider?:
    | CloudProvider
    | undefined;
  /** To be replaced by autoscaler_settings.min_containers */
  warmPoolSize: number;
  webUrl: string;
  webUrlInfo:
    | WebUrlInfo
    | undefined;
  /** If set, overrides the runtime used by the function, either "runc" or "gvisor". */
  runtime: string;
  /** Formerly stub_name */
  appName: string;
  volumeMounts: VolumeMount[];
  maxConcurrentInputs: number;
  customDomainInfo: CustomDomainInfo[];
  /** For internal debugging use only. */
  workerId: string;
  /** For internal debugging use only. */
  runtimeDebug: boolean;
  /** TODO: combine into enum? */
  isBuilderFunction: boolean;
  isAutoSnapshot: boolean;
  isMethod: boolean;
  isCheckpointingFunction: boolean;
  checkpointingEnabled: boolean;
  checkpoint: CheckpointInfo | undefined;
  objectDependencies: ObjectDependency[];
  blockNetwork: boolean;
  /**
   * In the SDK, we've deprecated `max_inputs` (which only every implemented `max_inputs=1`)
   * in favor of a boolean `single_use_containers` parameter.
   */
  maxInputs: number;
  s3Mounts: S3Mount[];
  cloudBucketMounts: CloudBucketMount[];
  schedulerPlacement?:
    | SchedulerPlacement
    | undefined;
  /** if "Function" is actually a class grouping multiple methods */
  isClass: boolean;
  /** for class methods use this function id instead for invocations - the *referenced* function should have is_class=True */
  useFunctionId: string;
  /** for class methods - this method name needs to be included in the FunctionInput */
  useMethodName: string;
  classParameterInfo:
    | ClassParameterInfo
    | undefined;
  /** Maximum number of inputs to fetch at once */
  batchMaxSize: number;
  /** Miliseconds to block before a response is needed */
  batchLingerMs: number;
  i6pnEnabled: boolean;
  ExperimentalConcurrentCancellations: boolean;
  targetConcurrentInputs: number;
  /** TODO(irfansharif): Remove, once https://github.com/modal-labs/modal/pull/15645 lands. */
  ExperimentalTaskTemplatesEnabled: boolean;
  /** for fallback options, where the first/most-preferred "template" is derived from fields above */
  ExperimentalTaskTemplates: TaskTemplate[];
  /**
   * When the function is a "grouped" one, this records the # of tasks we want
   * to schedule in tandem.
   */
  ExperimentalGroupSize: number;
  /** If set, the function will be run in an untrusted environment. */
  untrusted: boolean;
  /** To be replaced by autoscaler_settings.buffer_containers */
  ExperimentalBufferContainers: number;
  /**
   * _experimental_proxy_ip -> ProxyInfo
   * TODO: deprecate.
   */
  ExperimentalProxyIp?:
    | string
    | undefined;
  /** For internal debugging use only. */
  runtimePerfRecord: boolean;
  schedule:
    | Schedule
    | undefined;
  /** For internal debugging use only. */
  snapshotDebug: boolean;
  /** Mapping of method names to method definitions, only non-empty for class service functions */
  methodDefinitions: { [key: string]: MethodDefinition };
  methodDefinitionsSet: boolean;
  ExperimentalCustomScaling: boolean;
  /** Supersedes cloud_provider */
  cloudProviderStr: string;
  /** Experimental support for GPU snapshotting */
  ExperimentalEnableGpuSnapshot: boolean;
  /** Bundle of parameters related to autoscaling */
  autoscalerSettings:
    | AutoscalerSettings
    | undefined;
  /** Function schema, may be missing: client doesn't block deployment if it fails to get it */
  functionSchema:
    | FunctionSchema
    | undefined;
  /**
   * For server-side experimental functionality. Prefer using this over individual _experimental_* fields.
   * Note the value type as string. Internally we'll coerce all values to string with str().
   * On the server, it's necessary to convert back to the most natural type (e.g. int) when relevant.
   */
  experimentalOptions: { [key: string]: string };
  /**
   * If set, client deps will be mounted into the container, and are
   * no longer expected to exist in the image itself.
   */
  mountClientDependencies: boolean;
  flashServiceUrls: string[];
  flashServiceLabel: string;
  /** GPU memory snapshotting (alpha) */
  enableGpuSnapshot: boolean;
  startupTimeoutSecs: number;
  /** can be used as inputs */
  supportedInputFormats: DataFormat[];
  supportedOutputFormats: DataFormat[];
  httpConfig?:
    | HTTPConfig
    | undefined;
  /**
   * Attribute on the module with the implementation, which may differ from function_name
   * when the user provided a custom name= for the Function inside the Application namespace
   */
  implementationName: string;
  /** When True, containers will shut down after handling a single input */
  singleUseContainers: boolean;
  /** When True, the function is a server function */
  isServer: boolean;
}

export enum Function_DefinitionType {
  DEFINITION_TYPE_UNSPECIFIED = 0,
  DEFINITION_TYPE_SERIALIZED = 1,
  DEFINITION_TYPE_FILE = 2,
  UNRECOGNIZED = -1,
}

export function function_DefinitionTypeFromJSON(object: any): Function_DefinitionType {
  switch (object) {
    case 0:
    case "DEFINITION_TYPE_UNSPECIFIED":
      return Function_DefinitionType.DEFINITION_TYPE_UNSPECIFIED;
    case 1:
    case "DEFINITION_TYPE_SERIALIZED":
      return Function_DefinitionType.DEFINITION_TYPE_SERIALIZED;
    case 2:
    case "DEFINITION_TYPE_FILE":
      return Function_DefinitionType.DEFINITION_TYPE_FILE;
    case -1:
    case "UNRECOGNIZED":
    default:
      return Function_DefinitionType.UNRECOGNIZED;
  }
}

export function function_DefinitionTypeToJSON(object: Function_DefinitionType): string {
  switch (object) {
    case Function_DefinitionType.DEFINITION_TYPE_UNSPECIFIED:
      return "DEFINITION_TYPE_UNSPECIFIED";
    case Function_DefinitionType.DEFINITION_TYPE_SERIALIZED:
      return "DEFINITION_TYPE_SERIALIZED";
    case Function_DefinitionType.DEFINITION_TYPE_FILE:
      return "DEFINITION_TYPE_FILE";
    case Function_DefinitionType.UNRECOGNIZED:
    default:
      return "UNRECOGNIZED";
  }
}

export enum Function_FunctionType {
  FUNCTION_TYPE_UNSPECIFIED = 0,
  FUNCTION_TYPE_GENERATOR = 1,
  FUNCTION_TYPE_FUNCTION = 2,
  UNRECOGNIZED = -1,
}

export function function_FunctionTypeFromJSON(object: any): Function_FunctionType {
  switch (object) {
    case 0:
    case "FUNCTION_TYPE_UNSPECIFIED":
      return Function_FunctionType.FUNCTION_TYPE_UNSPECIFIED;
    case 1:
    case "FUNCTION_TYPE_GENERATOR":
      return Function_FunctionType.FUNCTION_TYPE_GENERATOR;
    case 2:
    case "FUNCTION_TYPE_FUNCTION":
      return Function_FunctionType.FUNCTION_TYPE_FUNCTION;
    case -1:
    case "UNRECOGNIZED":
    default:
      return Function_FunctionType.UNRECOGNIZED;
  }
}

export function function_FunctionTypeToJSON(object: Function_FunctionType): string {
  switch (object) {
    case Function_FunctionType.FUNCTION_TYPE_UNSPECIFIED:
      return "FUNCTION_TYPE_UNSPECIFIED";
    case Function_FunctionType.FUNCTION_TYPE_GENERATOR:
      return "FUNCTION_TYPE_GENERATOR";
    case Function_FunctionType.FUNCTION_TYPE_FUNCTION:
      return "FUNCTION_TYPE_FUNCTION";
    case Function_FunctionType.UNRECOGNIZED:
    default:
      return "UNRECOGNIZED";
  }
}

