export interface FunctionSchema {
  /** allows easy disambiguation between empty schema and no schema collection etc. */
  schemaType: FunctionSchema_FunctionSchemaType;
  arguments: ClassParameterSpec[];
  returnType: GenericPayloadType | undefined;
}

export enum FunctionSchema_FunctionSchemaType {
  FUNCTION_SCHEMA_UNSPECIFIED = 0,
  FUNCTION_SCHEMA_V1 = 1,
  UNRECOGNIZED = -1,
}

export function functionSchema_FunctionSchemaTypeFromJSON(object: any): FunctionSchema_FunctionSchemaType {
  switch (object) {
    case 0:
    case "FUNCTION_SCHEMA_UNSPECIFIED":
      return FunctionSchema_FunctionSchemaType.FUNCTION_SCHEMA_UNSPECIFIED;
    case 1:
    case "FUNCTION_SCHEMA_V1":
      return FunctionSchema_FunctionSchemaType.FUNCTION_SCHEMA_V1;
    case -1:
    case "UNRECOGNIZED":
    default:
      return FunctionSchema_FunctionSchemaType.UNRECOGNIZED;
  }
}

export function functionSchema_FunctionSchemaTypeToJSON(object: FunctionSchema_FunctionSchemaType): string {
  switch (object) {
    case FunctionSchema_FunctionSchemaType.FUNCTION_SCHEMA_UNSPECIFIED:
      return "FUNCTION_SCHEMA_UNSPECIFIED";
    case FunctionSchema_FunctionSchemaType.FUNCTION_SCHEMA_V1:
      return "FUNCTION_SCHEMA_V1";
    case FunctionSchema_FunctionSchemaType.UNRECOGNIZED:
    default:
      return "UNRECOGNIZED";
  }
}

