export interface Warning {
  type: Warning_WarningType;
  message: string;
}

export enum Warning_WarningType {
  WARNING_TYPE_UNSPECIFIED = 0,
  WARNING_TYPE_CLIENT_DEPRECATION = 1,
  WARNING_TYPE_RESOURCE_LIMIT = 2,
  WARNING_TYPE_FUNCTION_CONFIGURATION = 3,
  UNRECOGNIZED = -1,
}

export function warning_WarningTypeFromJSON(object: any): Warning_WarningType {
  switch (object) {
    case 0:
    case "WARNING_TYPE_UNSPECIFIED":
      return Warning_WarningType.WARNING_TYPE_UNSPECIFIED;
    case 1:
    case "WARNING_TYPE_CLIENT_DEPRECATION":
      return Warning_WarningType.WARNING_TYPE_CLIENT_DEPRECATION;
    case 2:
    case "WARNING_TYPE_RESOURCE_LIMIT":
      return Warning_WarningType.WARNING_TYPE_RESOURCE_LIMIT;
    case 3:
    case "WARNING_TYPE_FUNCTION_CONFIGURATION":
      return Warning_WarningType.WARNING_TYPE_FUNCTION_CONFIGURATION;
    case -1:
    case "UNRECOGNIZED":
    default:
      return Warning_WarningType.UNRECOGNIZED;
  }
}

export function warning_WarningTypeToJSON(object: Warning_WarningType): string {
  switch (object) {
    case Warning_WarningType.WARNING_TYPE_UNSPECIFIED:
      return "WARNING_TYPE_UNSPECIFIED";
    case Warning_WarningType.WARNING_TYPE_CLIENT_DEPRECATION:
      return "WARNING_TYPE_CLIENT_DEPRECATION";
    case Warning_WarningType.WARNING_TYPE_RESOURCE_LIMIT:
      return "WARNING_TYPE_RESOURCE_LIMIT";
    case Warning_WarningType.WARNING_TYPE_FUNCTION_CONFIGURATION:
      return "WARNING_TYPE_FUNCTION_CONFIGURATION";
    case Warning_WarningType.UNRECOGNIZED:
    default:
      return "UNRECOGNIZED";
  }
}

